INSERT
  INTO
       REVIEW
       (
	   REVIEW_NO
	 , USER_ID
	 , STATION_NO
	 , REVIEW_TITLE
	 , REVIEW_CONTENT
	 , RATING
	   )
VALUES
       (
	   SEQ_RVN.NEXTVAL
	 , #{userId}
	 , #{stationNo}
	 , #{reviewTitle}
	 , #{reviewContent}
	 , #{rating}  
	   )

mapper.update:
UPDATE
       REVIEW
   SET
       REVIEW_TITLE = #{reviewTitle}
     , REVIEW_CONTENT = #{reviewContent}
     , RATING = #{rating}
     , MODIFY_DATE = SYSTIMESTAMP
 WHERE
       REVIEW_NO = #{reviewNo}
   AND    
       STATUS = 'Y'
